#include <stdio.h>
#include <stdlib.h>

int main(){
    long long N; 
    if(scanf("%lld", &N)!=1) return 0;
    long long *A = malloc(N*sizeof(long long));
    for(long long i=0;i<N;i++) scanf("%lld", &A[i]);
    // store operations
    long long *ops = malloc(N*sizeof(long long)); // index of element to zero, 0 if not needed
    long long k=0;
    for(long long i=0;i<N;i++) if(A[i]!=0) ops[k++]=i+1; // 1‑based index
    printf("%lld\n", k);
    for(long long t=0;t<k;t++){
        printf("1\n%lld\n- %lld\n", ops[t], ops[t]);
    }
    free(A);
    free(ops);
    return 0;
}

