#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    ops = []
    for i, val in enumerate(A, start=1):
        if val != 0:
            ops.append(i)
    out = []
    out.append(str(len(ops)))
    for i in ops:
        out.append('1')
        out.append(str(i))
        out.append(f'- {i}')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

